1304→func (s *apiServer) ListMarketplaceServers(w http.ResponseWriter, r *http.Request, params api.ListMarketplaceServersParams) {
1305→	ctx := r.Context()
1306→
1307→	var query string
1308→	if params.Q != nil {
1309→		query = *params.Q
1310→	}
1311→
1312→	servers, err := s.registryClient.Search(ctx, query)
1313→	if err != nil {
1314→		writeError(w, http.StatusBadGateway, "registry_error", err.Error())
1315→		return
1316→	}
1317→
1318→	// Build a set of installed registry IDs for enrichment.
1319→	installed, _ := s.mcpServers.List(ctx, store.MCPServerFilter{})
1320→	installedSet := make(map[string]bool, len(installed))
1321→	for _, srv := range installed {
1322→		if srv.RegistryId != nil {
1323→			installedSet[*srv.RegistryId] = true
1324→		}
1325→	}
1326→
1327→	items := make([]api.MarketplaceServer, 0, len(servers))
1328→	for _, srv := range servers {
1329→		ms := api.MarketplaceServer{
1330→			RegistryId: srv.Name,
1331→			Name:       srv.Name,
1332→		}
1333→		if srv.Description != "" {
1334→			ms.Description = &srv.Description
1335→		}
1336→		if srv.Version != "" {
1337→			ms.Version = &srv.Version
1338→		}
1339→		isInstalled := installedSet[srv.Name]
1340→		ms.Installed = &isInstalled
1341→
1342→		// Collect required env vars from packages.
1343→		var envVars []api.RequiredEnvVar
1344→		for _, pkg := range srv.Packages {
1345→			for _, ev := range pkg.EnvVars {
1346→				envVars = append(envVars, api.RequiredEnvVar{
1347→					Name:        ev.Name,
1348→					Description: &ev.Description,
1349→					Required:    &ev.Required,
1350→				})
1351→			}
1352→		}
1353→		if len(envVars) > 0 {
1354→			ms.RequiredEnvVars = &envVars
1355→		}
1356→
1357→		items = append(items, ms)
1358→	}
1359→
1360→	writeJSON(w, http.StatusOK, map[string]any{"items": items})
1361→}
